if (!obj) continue;

if (!obj.userData.bimPickId) obj.userData.bimPickId = id;
applyRenderRole(obj, 'model');
obj.visible = !skipCat(e) && !skipLevel(e);

// FED-01: ghost any element resolved through a `link_model` link.
